-- Dev-only repeatable seed data for quick matching tests.
-- Loaded via %dev Flyway location: classpath:db/dev
-- Source: randomuser.me + Stack Overflow Developer Survey 2025

VALUES ('d0000000-0000-0000-0000-000000000011', 'USER', 'System: dev-seed-owner', 'System owner for synthetic dev seeds.', false, now(), now())
ON CONFLICT (id) DO UPDATE SET searchable = false, updated_at = now();

VALUES ('d1000000-0000-0000-0000-000000000011', 'dev-seed', 'system-owner', 'd0000000-0000-0000-0000-000000000011', false)
ON CONFLICT (id) DO NOTHING;

DELETE FROM mesh.mesh_node
WHERE node_type = 'USER' AND id <> 'd0000000-0000-0000-0000-000000000011';


-- Ensure active consent for matching on all seeded users.
DELETE FROM mesh.mesh_node_consent c
USING mesh.mesh_node n
WHERE c.node_id = n.id
  AND n.node_type = 'USER'
  AND n.id <> 'd0000000-0000-0000-0000-000000000011'
  AND c.scope = 'professional_matching';

SELECT n.id, 'professional_matching', now(), NULL, '1.0', NULL
FROM mesh.mesh_node n
WHERE n.node_type = 'USER'
  AND n.id <> 'd0000000-0000-0000-0000-000000000011';
